import{c as t,Q as e,j as i,m as r}from"./chunks/framework.BPKcPtvA.js";const m=JSON.parse('{"title":"Installation with Prism Launcher / MultiMC","description":"","frontmatter":{},"headers":[],"relativePath":"install/install_prism.md","filePath":"install/install_prism.md","lastUpdated":1778764647000}'),o={name:"install/install_prism.md"};function l(n,a,s,c,u,d){return e(),i("div",null,[...a[0]||(a[0]=[r('<h1 id="installation-with-prism-launcher-multimc" tabindex="-1">Installation with <a href="https://prismlauncher.org/" target="_blank" rel="noreferrer">Prism Launcher</a> / MultiMC <a class="header-anchor" href="#installation-with-prism-launcher-multimc" aria-label="Permalink to &quot;Installation with [Prism Launcher](https://prismlauncher.org/) / MultiMC&quot;">​</a></h1><div class="info custom-block"><p class="custom-block-title">INFO</p><p>Prism Launcher is recommended instead of MultiMC due to it automatically fixing many common issues that occur with MultiMC.</p></div><h2 id="installation" tabindex="-1">Installation <a class="header-anchor" href="#installation" aria-label="Permalink to &quot;Installation&quot;">​</a></h2><p>We recommend using the official modpack, which includes other allowed QoL and performance mods. Download it from <a href="./download#modpack">here</a>.</p><p>Then, open your launcher, and either drag the <code>.mrpack</code> file into the launcher, or go to <code>Add Instance</code> -&gt; <code>Import (from zip)</code>, and select it here. Finally, launch your new instance to play MCSR Ranked.</p><h2 id="updating-java" tabindex="-1">Updating Java <a class="header-anchor" href="#updating-java" aria-label="Permalink to &quot;Updating Java&quot;">​</a></h2><p>It is generally recommended that you update your Java version for better performance, mod compatibility, and to fix some issues.</p><ul><li>for Prism Launcher: check out <a href="https://gist.github.com/maskersss/0993754fb91686f78f8c000280699fa4" target="_blank" rel="noreferrer">this document</a> for a guide.</li><li>for MultiMC: check out the relevant section of <a href="https://docs.google.com/document/d/1PIjyPMulI3r5aZpfywt5OQR_12qEzX5UTfU8DQHtNp8/edit?" target="_blank" rel="noreferrer">this document</a>.</li></ul><h2 id="further-setup" tabindex="-1">Further Setup <a class="header-anchor" href="#further-setup" aria-label="Permalink to &quot;Further Setup&quot;">​</a></h2><p>Follow <a href="https://youtu.be/l-q-_4R8_6M" target="_blank" rel="noreferrer">Draconix&#39;s guide</a> for further setup. It is not required to watch to play MCSR Ranked but includes installation for various useful tools, including:</p><ul><li>Ninjabrainbot and eye measuring</li><li>Practice maps</li><li>MiniPracticeKit</li><li>Toolscreen (rebinding, resizing, projectors)</li></ul>',11)])])}const p=t(o,[["render",l]]);export{m as __pageData,p as default};
